const dates = input.match(/\b\d{4}-\d{2}-\d{2}\b/g) || [];
if (dates.length < 2) return { output: '', error: 'Please provide two dates in YYYY-MM-DD format.' };
const [d1, d2] = [new Date(dates[0]), new Date(dates[1])];
if (isNaN(d1) || isNaN(d2)) return { output: '', error: 'Could not parse dates.' };
const start = d1 < d2 ? d1 : d2;
const end   = d1 < d2 ? d2 : d1;
const msPerDay = 86400000;
const totalDays = Math.round((end - start) / msPerDay);
const totalWeeks = (totalDays / 7).toFixed(2);
const months = (end.getFullYear() - start.getFullYear()) * 12 + (end.getMonth() - start.getMonth());

// Business days (Mon-Fri)
let bizDays = 0;
const cur = new Date(start);
while (cur < end) {
  const dow = cur.getDay();
  if (dow !== 0 && dow !== 6) bizDays++;
  cur.setDate(cur.getDate() + 1);
}

const lines = [
  `From:           ${start.toISOString().slice(0, 10)}`,
  `To:             ${end.toISOString().slice(0, 10)}`,
  '',
  `Calendar days:  ${totalDays}`,
  `Weeks:          ${totalWeeks}`,
  `Approx months:  ${months}`,
  `Business days:  ${bizDays} (Mon–Fri)`,
];
return { output: lines.join('\n'), outputLanguage: 'text' };
